-- ============================================
-- Legislacao full-site: guilherme-derrite / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/204531
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = guilherme-derrite-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 101 rows Camara legacy existentes, somente 77
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=204531, tipo Deputado(a), ordemAssinatura=1.
-- 24 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'guilherme-derrite';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'guilherme-derrite: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 101 THEN
    RAISE EXCEPTION 'Pre-condicao guilherme-derrite: esperadas 101 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2586520', '2606630', '2590144', '2590049', '2586511', '2422073', '2333613', '2333526', '2604311', '2586593', '2585688', '2583051', '2421904', '2333786', '2333591', '2333384', '2604273', '2586588', '2584743', '2422755', '2333619', '2333618', '2333574', '2421414', '2336541', '2326355', '2312960', '2421002', '2333614', '2333553', '2329050', '2325732', '2309231', '2314529', '2310808', '2305554', '2303765', '2303767', '2295165', '2304381', '2303663', '2294877', '2330039', '2329049', '2309731', '2303769', '2583987', '2422515', '2333111', '2327313', '2325731', '2322282', '2305549', '2305203', '2303770', '2586516', '2422517', '2305329', '2327312', '2305550', '2314528', '2310807', '2295169', '2343503', '2312990', '2333590', '2307048', '2583386', '2421903', '2309012', '2307580', '2305547', '2295126', '2337502', '2310804', '2604376', '2310802');
  IF target_present <> 77 THEN
    RAISE EXCEPTION 'Pre-condicao guilherme-derrite: esperadas 77 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2586520', '2606630', '2590144', '2590049', '2586511', '2422073', '2333613', '2333526', '2604311', '2586593', '2585688', '2583051', '2421904', '2333786', '2333591', '2333384', '2604273', '2586588', '2584743', '2422755', '2333619', '2333618', '2333574', '2421414', '2336541', '2326355', '2312960', '2421002', '2333614', '2333553', '2329050', '2325732', '2309231', '2314529', '2310808', '2305554', '2303765', '2303767', '2295165', '2304381', '2303663', '2294877', '2330039', '2329049', '2309731', '2303769', '2583987', '2422515', '2333111', '2327313', '2325731', '2322282', '2305549', '2305203', '2303770', '2586516', '2422517', '2305329', '2327312', '2305550', '2314528', '2310807', '2295169', '2343503', '2312990', '2333590', '2307048', '2583386', '2421903', '2309012', '2307580', '2305547', '2295126', '2337502', '2310804', '2604376', '2310802')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'guilherme-derrite-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao guilherme-derrite: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao guilherme-derrite: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

